<div class="panel"><form method="post" action="<?=isset($user)?url('/users/'.$user['id']):url('/users')?>"><?=csrf_field()?><label>Nombre<input name="name" required value="<?=e($user['name']??'')?>"></label><label>Email<input type="email" name="email" required value="<?=e($user['email']??'')?>"></label><label>Contraseña<input type="password" name="password" <?=isset($user)?'':'required'?>></label><label>Rol<select name="role_id"><?php foreach($roles as $r): ?><option value="<?=$r['id']?>" <?=(($user['role_id']??'')==$r['id'])?'selected':''?>><?=e($r['name'])?></option><?php endforeach; ?></select></label><label>Estado<select name="status"><option value="active" <?=(($user['status']??'active')==='active')?'selected':''?>>Activo</option><option value="inactive" <?=(($user['status']??'')==='inactive')?'selected':''?>>Inactivo</option></select></label><button class="btn primary">Guardar</button></form></div>
